// Edit all user settings here. Do not edit any other node.
const settings = {
  SLACK_CHANNEL_ID: 'YOUR_SLACK_CHANNEL_ID',
  GOOGLE_SHEET_ID: 'YOUR_GOOGLE_SHEET_ID',
  SUPPORT_EMAIL: 'YOUR_SUPPORT_EMAIL',
  SHEET_NAME: 'Support Tickets',
  MAX_EMAIL_CHARS: 2000
};

return items.map(function(item) {
  return { json: Object.assign({}, item.json, { settings: settings }) };
});

var item = items[0].json;
var settings = item.settings;
var subject = item.subject || 'No subject';
var fromVal = item.from;
var fromEmail = '';
if (fromVal && fromVal.value && fromVal.value.length > 0) {
  fromEmail = fromVal.value[0].address || '';
} else if (typeof fromVal === 'string') {
  fromEmail = fromVal;
}
var rawBody = item.text || item.snippet || '';
var bodyTruncated = rawBody.length > settings.MAX_EMAIL_CHARS ? rawBody.slice(0, settings.MAX_EMAIL_CHARS) : rawBody;

var prompt = 'You are a customer support AI agent. Read the email below and respond ONLY with a valid JSON object, no other text before or after it.\n\n' +
  'FROM: ' + fromEmail + '\n' +
  'SUBJECT: ' + subject + '\n' +
  'BODY:\n' + bodyTruncated + '\n\n' +
  'Return exactly this JSON structure:\n' +
  '{"category":"one of billing, technical, general, refund, or complaint",' +
  '"priority":"one of urgent, normal, or low",' +
  '"sentiment":"one of frustrated, neutral, or positive",' +
  '"summary":"one sentence describing the issue",' +
  '"draft_reply":"professional plain text reply to send to the customer, no HTML, no greetings with first name placeholders",' +
  '"internal_note":"brief plain text note for the support team on how to handle this"}';

return [{ json: Object.assign({}, item, {
  prompt: prompt,
  fromEmail: fromEmail,
  emailSubject: subject
}) }];

var item = items[0].json;
var rawText = item.text || '';
var parsed = {};

try {
  var match = rawText.match(/\{[\s\S]*\}/);
  if (match) {
    parsed = JSON.parse(match[0]);
  }
} catch (e) {
  parsed = {
    category: 'general',
    priority: 'normal',
    sentiment: 'neutral',
    summary: 'Could not parse AI response. Manual review needed.',
    draft_reply: 'Thank you for contacting us. A member of our team will be in touch shortly.',
    internal_note: 'AI parsing failed on this ticket. Please review manually.'
  };
}

var now = new Date();
var processedAt = now.toISOString();

return [{ json: Object.assign({}, item, {
  priority: parsed.priority || 'normal',
  category: parsed.category || 'general',
  sentiment: parsed.sentiment || 'neutral',
  summary: parsed.summary || '',
  draft_reply: parsed.draft_reply || '',
  internal_note: parsed.internal_note || '',
  processedAt: processedAt,
  replySubject: 'Re: ' + (item.emailSubject || 'Your support request')
}) }];

var item = items[0].json;
var msg = 'URGENT support ticket received\n' +
  'From: ' + (item.fromEmail || 'unknown') + '\n' +
  'Subject: ' + (item.emailSubject || 'n/a') + '\n' +
  'Category: ' + (item.category || 'n/a') + '\n' +
  'Sentiment: ' + (item.sentiment || 'n/a') + '\n' +
  'Summary: ' + (item.summary || 'n/a') + '\n' +
  'Internal note: ' + (item.internal_note || 'n/a') + '\n' +
  'A draft reply has been created in Gmail. Review and send.';
return [{ json: Object.assign({}, item, { slackMessage: msg }) }];
